%%%%%%%%%% Function fAlsSynchPltV01.m %%%%%%%%%%% Function ALS Synchronization checking plot, ver.1% Kei Nakamura% Created on Wednesday, May 16th 2007.% Modified on %% function ok = fAlsSynchPltV01(hndl,y,ttl,xLbl,yLbl)% plot 3 figures to check synchronization, return hundles for plot% hndl: three hundles for figures% x, y: plot elements% ttl: 3 titles for plot% xLbl, yLbl: labelsfunction pHndl = fAlsSynchPltV01(hndl,x,y,ttl,xLbl,yLbl)  %function headersubplot(hndl(1));pHndl(1) = plot(x(1:end-1),y(2:end),'bo');title(ttl{1});xlabel(xLbl);ylabel(yLbl);a = axis;axis([0 a(2) 0 a(4)]);subplot(hndl(2));pHndl(2) = plot(x,y,'ro');title(ttl{2});xlabel(xLbl);ylabel(yLbl);a = axis;axis([0 a(2) 0 a(4)]);subplot(hndl(3));pHndl(3) = plot(x(2:end),y(1:end-1),'go');title(ttl{3});xlabel(xLbl);ylabel(yLbl);a = axis;axis([0 a(2) 0 a(4)]);
